    public static OrderStatus Shipped => EnumBase<OrderStatus>.EnumValue("Shipped");
    public static OrderStatus Delivered => EnumBase<OrderStatus>.EnumValue("Delivered");
    public static OrderStatus Cancelled => EnumBase<OrderStatus>.EnumValue("Cancelled");

    public static OrderStatus FromString(string status)
    {
